using System;

static bool IsPrime(int n) {
    if (n < 2) return false;
    for (int i = 2; i * i <= n; i++)
        if (n % i == 0) return false;
    return true;
}

static void TestCases() {
    var cases = new[] { (2, true), (3, true), (4, false), (17, true), (100, false) };
    int passed = 0;
    foreach (var (n, expected) in cases) {
        bool actual = IsPrime(n);
        if (actual != expected)
            Console.WriteLine($"FAIL: IsPrime({n}) = {actual}, expected {expected}");
        else {
            Console.WriteLine($"PASS: IsPrime({n}) = {actual}");
            passed++;
        }
    }
    Console.WriteLine($"{passed}/{cases.Length} passed");
}

class Program {
    static void Main() { TestCases(); }
}

using System;

static int Divide(int a, int b) {
    if (b == 0) throw new DivideByZeroException();
    return a / b;
}

static bool ThrowsExpected<T>(Action action) where T : Exception {
    try { action(); return false; }
    catch (T) { return true; }
    catch { return false; }
}

class Program {
    static void Main() {
        Console.WriteLine(Divide(10, 2));
        bool threw = ThrowsExpected<DivideByZeroException>(() => Divide(10, 0));
        Console.WriteLine($"threw DivideByZeroException: {threw}");
    }
}

using System;
using System.Collections.Generic;

static void RunAssertions() {
    // Equality
    var result = 2 + 2;
    if (result != 4) throw new Exception("equality failed");
    Console.WriteLine("PASS: equality");

    // Collection
    var list = new List<int> { 1, 2, 3 };
    if (!list.Contains(2)) throw new Exception("contains failed");
    Console.WriteLine("PASS: contains");

    // Null
    string s = null;
    if (s != null) throw new Exception("null check failed");
    Console.WriteLine("PASS: null");

    // Range
    int age = 25;
    if (age < 0 || age > 150) throw new Exception("range failed");
    Console.WriteLine("PASS: range");
}

class Program {
    static void Main() { RunAssertions(); }
}

using System;
using System.Collections.Generic;

class ShoppingCart {
    private List<(string name, decimal price)> items = new();
    public void Add(string name, decimal price) => items.Add((name, price));
    public decimal Total() => items.Aggregate(0m, (sum, item) => sum + item.price);
    public int Count => items.Count;
}

static void TestCartTotal() {
    // Arrange
    var cart = new ShoppingCart();
    cart.Add("Apple", 1.20m);
    cart.Add("Bread", 2.50m);
    // Act
    decimal total = cart.Total();
    // Assert
    if (total != 3.70m) throw new Exception($"Expected 3.70 got {total}");
    if (cart.Count != 2) throw new Exception($"Expected 2 items");
    Console.WriteLine("PASS: CartTotal");
}

class Program {
    static void Main() { TestCartTotal(); }
}

using System;

static string FizzBuzz(int n) {
    if (n % 15 == 0) return "FizzBuzz";
    if (n % 3 == 0) return "Fizz";
    if (n % 5 == 0) return "Buzz";
    return n.ToString();
}

static void TestFizzBuzz() {
    var cases = new[] {
        (1, "1"), (3, "Fizz"), (5, "Buzz"),
        (15, "FizzBuzz"), (7, "7"), (30, "FizzBuzz")
    };
    int pass = 0;
    foreach (var (n, expected) in cases) {
        string actual = FizzBuzz(n);
        if (actual == expected) { Console.WriteLine($"PASS: FizzBuzz({n})"); pass++; }
        else Console.WriteLine($"FAIL: FizzBuzz({n}) = {actual}, want {expected}");
    }
    Console.WriteLine($"{pass}/{cases.Length} passed");
}

class Program {
    static void Main() { TestFizzBuzz(); }
}

using System;

static string PadLeft(string s, int width) =>
    s.Length >= width ? s : new string(' ', width - s.Length) + s;

static void Test() {
    var cases = new[] {
        ("hi",    5, "   hi"),
        ("hello", 5, "hello"),
        ("toolong", 3, "toolong")
    };
    foreach (var (input, width, expected) in cases) {
        string actual = PadLeft(input, width);
        bool ok = actual == expected;
        Console.WriteLine($"{(ok ? "PASS" : "FAIL")}: PadLeft({input!.Length}, {width}) = '{actual}'");
    }
}

class Program {
    static void Main() { Test(); }
}

using System;
using System.Collections.Generic;

class Stack<T> {
    private List<T> items = new();
    public void Push(T item) => items.Add(item);
    public T Pop() => items.Count > 0 ? items[^1] : throw new InvalidOperationException("empty");
    public int Count => items.Count;
    public bool IsEmpty => items.Count == 0;
}

static void TestStack() {
    var s = new Stack<int>();
    if (!s.IsEmpty) throw new Exception("should be empty");
    s.Push(1); s.Push(2); s.Push(3);
    if (s.Count != 3) throw new Exception("count wrong");
    if (s.Pop() != 3) throw new Exception("LIFO wrong");
    Console.WriteLine("PASS: Stack<int>");
}

class Program {
    static void Main() { TestStack(); }
}
